      async acceptInvitation(token, userId) {
        const invitation = await this.getInvitationByToken(token);
        if (!invitation) throw new Error("Invitation not found");
        if (invitation.status !== "pending") throw new Error("Invitation already used");
        if (new Date(invitation.expiresAt) < /* @__PURE__ */ new Date()) throw new Error("Invitation expired");
        db.prepare("UPDATE org_invitations SET status = 'accepted', acceptedAt = ? WHERE id = ?").run(now2(), invitation.id);
        await this.addOrgMember(invitation.organizationId, userId, invitation.role, invitation.invitedBy);
        return invitation;
      }
